  @shape  clip.single = { mode='single', type, numRows, events=[clipEvent,...] }  @ 18
  @shape  clip.multi  = { mode='multi', numRows, startType, cols=[clipColEntry,...] }  @ 20
  @shape  clipColEntry = { type, chanDelta, key, events=[clipEvent,...] }  @ 21
